@Composable
fun SplashScreen() {
    var animationJson by remember { mutableStateOf("") }

    LaunchedEffect(Unit) {
        animationJson = withContext(Dispatchers.Default) {
            Res.readBytes("files/finance_loading_2.json").decodeToString()
        }
    }

    val composition = rememberKottieComposition(
        spec = KottieCompositionSpec.File(animationJson)
    )

    val animationState by animateKottieCompositionAsState(
        composition = composition,
        isPlaying = true
    )

    Scaffold(
        modifier = Modifier
            .fillMaxSize()
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .background(Color(0xFFF5F5F6))
                .padding(paddingValues),
            verticalArrangement = Arrangement.Center,
            horizontalAlignment = Alignment.CenterHorizontally
        ) {
            KottieAnimation(
                composition = composition,
                progress = { animationState.progress },
                modifier = Modifier
                    .size(240.dp)
            )
        }
    }
}
